/**
 * Package the locally-built AVR toolchain + SDK into static fixtures the browser
 * build worker can load (Stage 2 in-browser compile proof). Output is gitignored
 * and regenerated by `pnpm toolchain-fixtures`; the e2e skips if it's absent.
 *
 *   public/toolchain/{cc1,cc1plus,avr-as,avr-ld,avr-objcopy}.mjs  emscripten modules
 *   public/toolchain/sdk.json                                     headers+libs (base64)
 *   public/toolchain/manifest.json                                file list
 *
 * Tools are the SINGLE_FILE Emscripten ES modules (wasm embedded). The worker
 * blob-imports each. The SDK bundle carries every header + the link archives.
 */
import {
  existsSync,
  mkdirSync,
  readFileSync,
  writeFileSync,
  readdirSync,
  statSync,
  rmSync,
  copyFileSync,
} from 'node:fs';
import { createHash } from 'node:crypto';
import { fileURLToPath } from 'node:url';
import { dirname, join, relative } from 'node:path';

const root = dirname(fileURLToPath(import.meta.url)) + '/..';
const OUT = join(root, 'ci', 'toolchain-builder', 'out');
const SDK = join(OUT, 'arduino-avr-core');
const DST = join(root, 'packages', 'app', 'public', 'toolchain');

if (!existsSync(join(OUT, 'gcc', 'cc1plus'))) {
  console.error(
    'toolchain not built (ci/toolchain-builder/out/gcc/cc1plus missing) — run the toolchain build first',
  );
  process.exit(1);
}

rmSync(DST, { recursive: true, force: true });
mkdirSync(DST, { recursive: true });

// 1. Tools — copy the emscripten ES modules with a .mjs extension (ESM in the browser).
const tools = {
  cc1: join(OUT, 'gcc', 'cc1'),
  cc1plus: join(OUT, 'gcc', 'cc1plus'),
  'avr-as': join(OUT, 'binutils', 'avr-as'),
  'avr-ld': join(OUT, 'binutils', 'avr-ld'),
  'avr-objcopy': join(OUT, 'binutils', 'avr-objcopy'),
};
for (const [name, src] of Object.entries(tools)) copyFileSync(src, join(DST, `${name}.mjs`));

// 2. SDK bundle — headers (by mount) + link archives, base64-encoded.
// avr-libc ships per-device register headers (avr/iom328p.h, avr/iotn85.h, …) for
// EVERY AVR — ~28MB. atmega328p only needs avr/io.h (the dispatcher) + iom328p.h, so
// drop the other device headers to keep the bundle small.
function keepHeader(rel) {
  const m = rel.match(/^avr\/io([^/]+)\.h$/);
  if (!m) return true;
  return rel === 'avr/io.h' || rel === 'avr/iom328p.h' || rel === 'avr/iom328pb.h';
}
function walk(dir, base = dir, acc = [], filter = () => true) {
  for (const n of readdirSync(dir)) {
    const p = join(dir, n);
    if (statSync(p).isDirectory()) walk(p, base, acc, filter);
    else {
      const rel = relative(base, p);
      if (filter(rel)) acc.push({ path: rel, b64: readFileSync(p).toString('base64') });
    }
  }
  return acc;
}
const b64 = (p) => readFileSync(p).toString('base64');
const sdk = {
  headerMounts: [
    { mount: '/sdk/core', files: walk(join(SDK, 'headers', 'core')) },
    { mount: '/sdk/variant', files: walk(join(SDK, 'headers', 'variant')) },
    {
      mount: '/sdk/avr-libc',
      files: walk(join(SDK, 'headers', 'avr-libc'), undefined, [], keepHeader),
    },
    { mount: '/sdk/gcc', files: walk(join(SDK, 'headers', 'gcc')) },
  ],
  crt: b64(join(SDK, 'lib', 'crtatmega328p.o')),
  coreA: b64(join(SDK, 'lib', 'core.a')),
  libs: ['libgcc.a', 'libm.a', 'libc.a', 'libatmega328p.a'].map((name) => ({
    name,
    b64: b64(join(SDK, 'lib', 'avr5', name)),
  })),
  ldscript: readFileSync(
    join(root, 'packages', 'emulators', 'test-fixtures', 'avr5-ld.x'),
  ).toString('base64'),
};
writeFileSync(join(DST, 'sdk.json'), JSON.stringify(sdk));

// 3. Preset libraries — headers (mounted) + AVR sources (compiled as units). Only the
// AVR-relevant files are packaged; arch guards keep the rest unused. Skips a library
// whose source tree isn't present locally (e.g. user hasn't installed it).
const USER_LIBS = join(root, '.tools', 'arduino-user', 'libraries');
const WIRE_SRC = join(
  root,
  '.tools',
  'arduino15',
  'packages',
  'arduino',
  'hardware',
  'avr',
  '1.8.8',
  'libraries',
  'Wire',
  'src',
);
const LIB_SPECS = [
  {
    name: 'Wire',
    version: '1.0',
    provides: ['Wire.h'],
    depends: [],
    dir: WIRE_SRC,
    includeSubdirs: ['', 'utility'],
    headers: ['Wire.h', 'utility/twi.h'],
    sources: [
      { rel: 'Wire.cpp', language: 'c++' },
      { rel: 'utility/twi.c', language: 'c' },
    ],
  },
  {
    name: 'Servo',
    version: '1.2.2',
    provides: ['Servo.h'],
    depends: [],
    dir: join(USER_LIBS, 'Servo', 'src'),
    includeSubdirs: [''],
    headers: ['Servo.h', 'avr/ServoTimers.h'],
    sources: [{ rel: 'avr/Servo.cpp', language: 'c++' }],
  },
  {
    name: 'LiquidCrystal_I2C',
    version: '1.1.2',
    provides: ['LiquidCrystal_I2C.h'],
    depends: ['Wire'],
    dir: join(USER_LIBS, 'LiquidCrystal_I2C'),
    includeSubdirs: [''],
    headers: ['LiquidCrystal_I2C.h'],
    sources: [{ rel: 'LiquidCrystal_I2C.cpp', language: 'c++' }],
  },
  {
    // The basic DHT class (DHT.cpp) is standalone, but the library DECLARES a
    // dependency on Adafruit Unified Sensor — packaged so transitive resolution
    // pulls it the way arduino-cli does.
    name: 'DHT',
    version: '1.4.6',
    provides: ['DHT.h', 'DHT_U.h'],
    depends: ['Adafruit_Unified_Sensor'],
    dir: join(USER_LIBS, 'DHT_sensor_library'),
    includeSubdirs: [''],
    headers: ['DHT.h', 'DHT_U.h'],
    sources: [{ rel: 'DHT.cpp', language: 'c++' }],
  },
  {
    name: 'Adafruit_Unified_Sensor',
    version: '1.1.14',
    provides: ['Adafruit_Sensor.h'],
    depends: [],
    dir: join(USER_LIBS, 'Adafruit_Unified_Sensor'),
    includeSubdirs: [''],
    headers: ['Adafruit_Sensor.h'],
    sources: [{ rel: 'Adafruit_Sensor.cpp', language: 'c++' }],
  },
];
const libraries = [];
for (const spec of LIB_SPECS) {
  if (
    !spec.sources.every((s) => existsSync(join(spec.dir, s.rel))) ||
    !spec.headers.every((h) => existsSync(join(spec.dir, h)))
  ) {
    console.warn(`  (skip library ${spec.name}: sources not present)`);
    continue;
  }
  const mount = `/lib/${spec.name}`;
  libraries.push({
    name: spec.name,
    version: spec.version,
    provides: spec.provides,
    depends: spec.depends,
    mount,
    includePaths: spec.includeSubdirs.map((s) => (s ? `${mount}/${s}` : mount)),
    headers: spec.headers.map((h) => ({ path: h, b64: b64(join(spec.dir, h)) })),
    sources: spec.sources.map((s) => ({
      path: `${mount}/${s.rel}`,
      b64: b64(join(spec.dir, s.rel)),
      language: s.language,
    })),
  });
}
writeFileSync(join(DST, 'libraries.json'), JSON.stringify(libraries));
console.log(`  libraries packaged: ${libraries.map((l) => l.name).join(', ') || '(none)'}`);

// buildId = content hash of the SDK + libraries (everything besides the compiler
// binaries that affects output; the tools are identified by compilerId in the cache
// key). The browser folds this in so the firmware cache auto-invalidates whenever the
// SDK/library fixtures are regenerated (reproducibility, I5).
const buildId = `sha256:${createHash('sha256')
  .update(readFileSync(join(DST, 'sdk.json')))
  .update(readFileSync(join(DST, 'libraries.json')))
  .digest('hex')}`;

writeFileSync(
  join(DST, 'manifest.json'),
  JSON.stringify(
    {
      buildId,
      tools: Object.keys(tools).map((t) => `${t}.mjs`),
      sdk: 'sdk.json',
      libraries: 'libraries.json',
    },
    null,
    2,
  ),
);

// Integrity manifest (AUD-013): pin every self-hosted asset (the 5 compiler/binutils modules + sdk.json +
// libraries.json) so the loader rejects a tampered/substituted byte BEFORE blob-importing/executing it.
const sha256 = (name) =>
  createHash('sha256')
    .update(readFileSync(join(DST, name)))
    .digest('hex');
const integrity = {};
for (const t of Object.keys(tools)) integrity[`${t}.mjs`] = sha256(`${t}.mjs`);
integrity['sdk.json'] = sha256('sdk.json');
integrity['libraries.json'] = sha256('libraries.json');
writeFileSync(join(DST, 'integrity.json'), JSON.stringify(integrity));

let total = 0;
for (const n of readdirSync(DST)) total += statSync(join(DST, n)).size;
console.log(
  `toolchain fixtures written to ${DST} (${(total / 1e6).toFixed(1)} MB raw; Vite serves gzipped)`,
);
